export * from "./entities/index.js";
export * from "./protocol.js";
export * from "./vocab/index.js";

export * from "./common.js";
export * from "./enemies.js";
export * from "./items.js";
export * from "./narration.js";
export * from "./npcs.js";
export * from "./quests.js";
export * from "./traps.js";

import { z } from "zod";

import { bounds } from "../../config/index.js";
import {
  boundedInt,
  enforceActivePayload,
  glyphSchema,
  nonEmptyString,
} from "../common.js";
import { EffectBundleSchema } from "../vocab/index.js";
import {
  DepthBandSchema,
  EntityNameSchema,
  OriginTagSchema,
  type DepthBand,
} from "./common.js";

export const EnemyStatBlockSchema = z
  .strictObject({
    band: DepthBandSchema,
    hp: z.number().int(),
    attack: z.number().int(),
    defense: z.number().int(),
    xpYield: z.number().int(),
  })
  .superRefine((stats, ctx) => {
    const statBounds = bounds.enemyDesign.statBudgetsByBand[stats.band];

    enforceStatBound(ctx, ["hp"], stats.hp, statBounds.hp);
    enforceStatBound(ctx, ["attack"], stats.attack, statBounds.attack);
    enforceStatBound(ctx, ["defense"], stats.defense, statBounds.defense);
    enforceStatBound(ctx, ["xpYield"], stats.xpYield, statBounds.xpYield);
  });

export type EnemyStatBlock = z.infer<typeof EnemyStatBlockSchema>;

export const BEHAVIOR_IDS =
  bounds.enemyDesign.behaviorVocabulary.closedList;

export const BehaviorKindSchema = z.enum(BEHAVIOR_IDS);

export type BehaviorKind = z.infer<typeof BehaviorKindSchema>;

export const EmptyBehaviorPayloadSchema = z.strictObject({});

export const KeepRangeBehaviorPayloadSchema = z.strictObject({
  distanceTiles: boundedInt(
    bounds.enemyDesign.behaviorVocabulary.parameters.keepRangeDistanceTiles,
  ),
});

export const FleeLowHpBehaviorPayloadSchema = z.strictObject({
  thresholdPercent: boundedInt(
    bounds.enemyDesign.behaviorVocabulary.parameters.fleeLowHpThresholdPercent,
  ),
});

export const PackHunterBehaviorPayloadSchema = z.strictObject({
  allyCount: boundedInt({
    min: bounds.enemyDesign.behaviorVocabulary.parameters.packHunter.allyCountMin,
    max: bounds.enemyDesign.behaviorVocabulary.parameters.packHunter.allyCountMax,
  }),
});

export const AmbusherBehaviorPayloadSchema = z.strictObject({
  wakeRadiusTiles: boundedInt(
    bounds.enemyDesign.behaviorVocabulary.parameters.ambusherWakeRadiusTiles,
  ),
});

export const TerritorialBehaviorPayloadSchema = z.strictObject({
  radiusTiles: boundedInt(
    bounds.enemyDesign.behaviorVocabulary.parameters.territorialRadiusTiles,
  ),
});

export const GuardBehaviorPayloadSchema = z.strictObject({
  tetherId: nonEmptyString,
  tetherRadiusTiles: boundedInt(
    bounds.enemyDesign.behaviorVocabulary.parameters.guardTetherRadiusTiles,
  ),
});

export const CasterBehaviorPayloadSchema = z.strictObject({
  cooldownTurns: boundedInt(
    bounds.enemyDesign.behaviorVocabulary.parameters.casterCooldownTurns,
  ),
});

const BEHAVIOR_PAYLOAD_KEYS = [
  "approachMelee",
  "keepRange",
  "fleeLowHp",
  "packHunter",
  "ambusher",
  "territorial",
  "guard",
  "patrol",
  "thief",
  "caster",
  "bodyguard",
  "mimic",
] as const;

const BEHAVIOR_PAYLOAD_FIELD_BY_KIND = {
  approach_melee: "approachMelee",
  keep_range: "keepRange",
  flee_low_hp: "fleeLowHp",
  pack_hunter: "packHunter",
  ambusher: "ambusher",
  territorial: "territorial",
  guard: "guard",
  patrol: "patrol",
  thief: "thief",
  caster: "caster",
  bodyguard: "bodyguard",
  mimic: "mimic",
} as const satisfies Record<
  BehaviorKind,
  (typeof BEHAVIOR_PAYLOAD_KEYS)[number]
>;

// Provider-facing: required nullable payload fields avoid a root union.
export const BehaviorSchema = z
  .strictObject({
    kind: BehaviorKindSchema,
    approachMelee: EmptyBehaviorPayloadSchema.nullable(),
    keepRange: KeepRangeBehaviorPayloadSchema.nullable(),
    fleeLowHp: FleeLowHpBehaviorPayloadSchema.nullable(),
    packHunter: PackHunterBehaviorPayloadSchema.nullable(),
    ambusher: AmbusherBehaviorPayloadSchema.nullable(),
    territorial: TerritorialBehaviorPayloadSchema.nullable(),
    guard: GuardBehaviorPayloadSchema.nullable(),
    patrol: EmptyBehaviorPayloadSchema.nullable(),
    thief: EmptyBehaviorPayloadSchema.nullable(),
    caster: CasterBehaviorPayloadSchema.nullable(),
    bodyguard: EmptyBehaviorPayloadSchema.nullable(),
    mimic: EmptyBehaviorPayloadSchema.nullable(),
  })
  .superRefine((behavior, ctx) => {
    enforceActivePayload(
      behavior,
      ctx,
      BEHAVIOR_PAYLOAD_KEYS,
      BEHAVIOR_PAYLOAD_FIELD_BY_KIND[behavior.kind],
    );
  });

export type Behavior = z.infer<typeof BehaviorSchema>;

// Provider-facing: abilities are effect bundles; behavior parameters remain bounded.
export const EnemyDefinitionSchema = z.strictObject({
  id: nonEmptyString,
  name: EntityNameSchema,
  glyph: glyphSchema,
  origin: OriginTagSchema,
  stats: EnemyStatBlockSchema,
  behaviors: z
    .array(BehaviorSchema)
    .min(bounds.enemyDesign.behaviorsPerEnemy.min)
    .max(bounds.enemyDesign.behaviorsPerEnemy.max),
  abilities: z
    .array(EffectBundleSchema)
    .min(bounds.enemyDesign.abilitiesPerEnemy.min)
    .max(bounds.enemyDesign.abilitiesPerEnemy.max),
});

export type EnemyDefinition = z.infer<typeof EnemyDefinitionSchema>;

const enforceStatBound = (
  ctx: z.RefinementCtx,
  path: string[],
  value: number,
  range: { readonly min: number; readonly max: number },
): void => {
  if (value < range.min) {
    ctx.addIssue({
      code: "custom",
      path,
      message: `must be at least ${range.min}`,
    });
  }

  if (value > range.max) {
    ctx.addIssue({
      code: "custom",
      path,
      message: `must be at most ${range.max}`,
    });
  }
};

export const enemyStatBoundsForBand = (band: DepthBand) =>
  bounds.enemyDesign.statBudgetsByBand[band];

import { z } from "zod";

import { bounds, config } from "../../config/index.js";
import {
  boundedInt,
  enforceActivePayload,
  glyphSchema,
  nonEmptyString,
} from "../common.js";
import { EffectBundleSchema, type EffectBundle } from "../vocab/index.js";
import {
  DepthBandSchema,
  EntityNameSchema,
  ItemCategorySchema,
  type DepthBand,
  type ItemCategory,
} from "./common.js";

export const ItemValueSchema = z
  .strictObject({
    band: DepthBandSchema,
    coin: z.number().int(),
  })
  .superRefine((value, ctx) => {
    const valueBounds = config.itemsEconomy.valueBandsCoin[value.band];

    if (value.coin < valueBounds.min) {
      ctx.addIssue({
        code: "custom",
        path: ["coin"],
        message: `${value.band} item value must be at least ${valueBounds.min}`,
      });
    }

    if (value.coin > valueBounds.max) {
      ctx.addIssue({
        code: "custom",
        path: ["coin"],
        message: `${value.band} item value must be at most ${valueBounds.max}`,
      });
    }
  });

export const WeaponOnHitProcSchema = z
  .strictObject({
    chancePercent: boundedInt(
      bounds.effectVocabulary.triggers.procChancePercent.onHit,
    ),
    bundle: EffectBundleSchema,
  })
  .superRefine((proc, ctx) => {
    enforceProcBundle(proc.bundle, "on_hit", proc.chancePercent, ctx);
  });

export const ArmorOnStruckProcSchema = z
  .strictObject({
    chancePercent: boundedInt(
      bounds.effectVocabulary.triggers.procChancePercent.onStruck,
    ),
    bundle: EffectBundleSchema,
  })
  .superRefine((proc, ctx) => {
    enforceProcBundle(proc.bundle, "on_struck", proc.chancePercent, ctx);
  });

export const WeaponItemPayloadSchema = z.strictObject({
  attackBonus: boundedInt(bounds.itemsEconomy.weaponAtkBonus),
  cursed: z.boolean(),
  onHit: WeaponOnHitProcSchema.nullable(),
});

export const ArmorItemPayloadSchema = z.strictObject({
  defenseBonus: boundedInt(bounds.itemsEconomy.armorDefBonus),
  cursed: z.boolean(),
  onStruck: ArmorOnStruckProcSchema.nullable(),
});

export const CharmItemPayloadSchema = z
  .strictObject({
    passive: EffectBundleSchema,
    cursed: z.boolean(),
  })
  .superRefine((payload, ctx) => {
    enforceCharmPassive(payload.passive, ctx);
  });

export const DraughtItemPayloadSchema = z.strictObject({
  effect: EffectBundleSchema,
});

export const NoteItemPayloadSchema = z.strictObject({
  effect: EffectBundleSchema,
});

export const ThrowableItemPayloadSchema = z.strictObject({
  effect: EffectBundleSchema,
});

export const FoodItemPayloadSchema = z.strictObject({
  effect: EffectBundleSchema,
});

export const ToolItemPayloadSchema = z.strictObject({
  effect: EffectBundleSchema,
});

export const KeyItemPayloadSchema = z.strictObject({
  questHookId: nonEmptyString.nullable(),
});

export const CoinItemPayloadSchema = z.strictObject({});

const ITEM_PAYLOAD_KEYS = [
  "weapon",
  "armor",
  "charm",
  "draught",
  "note",
  "throwable",
  "food",
  "tool",
  "keyItem",
  "coin",
] as const;

const ITEM_PAYLOAD_FIELD_BY_KIND = {
  weapon: "weapon",
  armor: "armor",
  charm: "charm",
  draught: "draught",
  note: "note",
  throwable: "throwable",
  food: "food",
  tool: "tool",
  key_item: "keyItem",
  coin: "coin",
} as const satisfies Record<ItemCategory, (typeof ITEM_PAYLOAD_KEYS)[number]>;

// Provider-facing: required nullable payload fields avoid a root union.
export const ItemDefinitionSchema = z
  .strictObject({
    id: nonEmptyString,
    name: EntityNameSchema,
    glyph: glyphSchema,
    kind: ItemCategorySchema,
    value: ItemValueSchema,
    weapon: WeaponItemPayloadSchema.nullable(),
    armor: ArmorItemPayloadSchema.nullable(),
    charm: CharmItemPayloadSchema.nullable(),
    draught: DraughtItemPayloadSchema.nullable(),
    note: NoteItemPayloadSchema.nullable(),
    throwable: ThrowableItemPayloadSchema.nullable(),
    food: FoodItemPayloadSchema.nullable(),
    tool: ToolItemPayloadSchema.nullable(),
    keyItem: KeyItemPayloadSchema.nullable(),
    coin: CoinItemPayloadSchema.nullable(),
  })
  .superRefine((item, ctx) => {
    enforceActivePayload(
      item,
      ctx,
      ITEM_PAYLOAD_KEYS,
      ITEM_PAYLOAD_FIELD_BY_KIND[item.kind],
    );
  });

export type ItemDefinition = z.infer<typeof ItemDefinitionSchema>;

const enforceProcBundle = (
  bundle: EffectBundle,
  triggerKind: "on_hit" | "on_struck",
  chancePercent: number,
  ctx: z.RefinementCtx,
): void => {
  if (bundle.trigger.kind !== triggerKind) {
    ctx.addIssue({
      code: "custom",
      path: ["bundle", "trigger", "kind"],
      message: `proc bundle trigger must be ${triggerKind}`,
    });
    return;
  }

  const triggerChancePercent =
    triggerKind === "on_hit"
      ? bundle.trigger.onHit?.procChancePercent
      : bundle.trigger.onStruck?.procChancePercent;

  if (triggerChancePercent !== chancePercent) {
    ctx.addIssue({
      code: "custom",
      path: ["bundle", "trigger"],
      message: "proc chancePercent must match bundle trigger chance",
    });
  }
};

const enforceCharmPassive = (
  passive: EffectBundle,
  ctx: z.RefinementCtx,
): void => {
  if (passive.effects.length !== bounds.itemsEconomy.charmEquipPassiveEffects) {
    ctx.addIssue({
      code: "custom",
      path: ["passive", "effects"],
      message: `charm passive must contain exactly ${bounds.itemsEconomy.charmEquipPassiveEffects} effect`,
    });
  }

  if (passive.trigger.kind !== "equip_passive") {
    ctx.addIssue({
      code: "custom",
      path: ["passive", "trigger", "kind"],
      message: "charm passive trigger must be equip_passive",
    });
  }
};

export const itemValueBoundsForBand = (band: DepthBand) =>
  config.itemsEconomy.valueBandsCoin[band];

